    def create_cricket_vocab() -> 'CricketTokenizerVocab':
        """Create specialized vocabulary for cricket domain."""
        cricket_terms = [
            'Rohit', 'Sharma', 'Jasprit', 'Bumrah', 'Virat', 'Kohli',
            'wicket', 'innings', 'over', 'delivery', 'bowler', 'batter',
            'run', 'boundary', 'yorker', 'bouncer', 'maiden', 'powerplay',
            'DRS', 'stumps', 'crease', 'fielding', 'catch', 'lbw'
        ]
        vocab_dict = {term: idx for idx, term in enumerate(cricket_terms)}
        reverse_vocab = {idx: term for term, idx in vocab_dict.items()}
        return CricketTokenizerVocab(vocab_dict, reverse_vocab, len(cricket_terms))

